            if(tags.isNotEmpty) {
               _removeKeyFromTags(key, tags);
            }
            return null;
         } else {
            return entry;
         }
      }
      return null;
   }
   Future<void> _invalidateByTags(List<String> tags) async {
      for (var tag in tags) {
         final tagKey = "${tagKeyPrefix}${tag}";
         final lock = _tagLocks[tag]!;
         await lock.synchronized(() async
         {
